+/// Coarse dietary classification used for debug surfacing.
+#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq, Default)]
+pub enum DietClass {
+    #[default]
+    Herbivore,
+    Omnivore,
+    Carnivore,
+}
+
+impl DietClass {
+    #[must_use]
+    pub fn from_tendency(tendency: f32) -> Self {
+        if tendency <= 0.33 {
+            Self::Herbivore
+        } else if tendency >= 0.66 {
+            Self::Carnivore
+        } else {
+            Self::Omnivore
+        }
+    }
+}
